let estagiosCount=1;document.addEventListener("DOMContentLoaded",()=>{const navLinks=document.querySelectorAll(".nav-link");const sections=document.querySelectorAll(".section");navLinks.forEach(link=>{link.addEventListener("click",e=>{e.preventDefault();const targetId=link.getAttribute("data-target");navLinks.forEach(l=>l.classList.remove("active"));link.classList.add("active");sections.forEach(section=>{section.classList.remove("active");if(section.id===targetId){section.classList.add("active")}})})});const adicionarEstagio=document.getElementById("adicionar-estagio");const estagiosContainer=document.getElementById("estagios-container");adicionarEstagio.addEventListener("click",()=>{const index=estagiosCount;estagiosCount++;const estagioHtml=`\n            <div class="estagio-item" data-index="${index}">\n                <div class="estagio-header">\n                    <h4>Estágio ${estagiosCount}</h4>\n                    <button type="button" class="btn-icon remover-estagio"><i class="fas fa-trash"></i></button>\n                </div>\n                <div class="estagio-body">\n                    <div class="form-row">\n                        <div class="form-group">\n                            <label for="velocidade-${index}">Velocidade (km/h)*</label>\n                            <input type="number" id="velocidade-${index}" name="estagios[${index}][velocidade]" step="0.1" min="0" required>\n                        </div>\n                        <div class="form-group">\n                            <label for="lactato-${index}">Lactato (mmol/L)*</label>\n                            <input type="number" id="lactato-${index}" name="estagios[${index}][lactato]" step="0.1" min="0" required>\n                        </div>\n                    </div>\n                    <div class="form-row">\n                        <div class="form-group">\n                            <label for="fc-media-${index}">FC Média</label>\n                            <input type="number" id="fc-media-${index}" name="estagios[${index}][fcMedia]" min="0">\n                        </div>\n                        <div class="form-group">\n                            <label for="fc-final-${index}">FC Final</label>\n                            <input type="number" id="fc-final-${index}" name="estagios[${index}][fcFinal]" min="0">\n                        </div>\n                        <div class="form-group">\n                            <label for="pse-${index}">PSE (0-10)</label>\n                            <input type="number" id="pse-${index}" name="estagios[${index}][pse]" min="0" max="10" step="1">\n                        </div>\n                    </div>\n                </div>\n            </div>\n        `;estagiosContainer.insertAdjacentHTML("beforeend",estagioHtml);adicionarEventosRemoverEstagio();adicionarEventosDetectarLimiares()});function adicionarEventosRemoverEstagio(){const removerBtns=document.querySelectorAll(".remover-estagio");removerBtns.forEach(btn=>{btn.addEventListener("click",e=>{const estagioItem=e.target.closest(".estagio-item");if(document.querySelectorAll(".estagio-item").length>1){estagioItem.remove();atualizarNumeracaoEstagios();detectarLimiares()}})})}function adicionarEventosDetectarLimiares(){const inputsLactato=document.querySelectorAll('input[name*="[lactato]"]');const inputsFcMedia=document.querySelectorAll('input[name*="[fcMedia]"]');const inputsVelocidade=document.querySelectorAll('input[name*="[velocidade]"]');inputsLactato.forEach(input=>{input.addEventListener("input",detectarLimiares)});inputsFcMedia.forEach(input=>{input.addEventListener("input",detectarLimiares)});inputsVelocidade.forEach(input=>{input.addEventListener("input",detectarLimiares)})}adicionarEventosRemoverEstagio();adicionarEventosDetectarLimiares();function atualizarNumeracaoEstagios(){const estagioItems=document.querySelectorAll(".estagio-item");estagioItems.forEach((item,index)=>{const header=item.querySelector(".estagio-header h4");header.textContent=`Estágio ${index+1}`})}function detectarLimiares(){const estagioItems=document.querySelectorAll(".estagio-item");const estagios=[];estagioItems.forEach(item=>{const index=item.getAttribute("data-index");const velocidadeInput=document.getElementById(`velocidade-${index}`);const lactatoInput=document.getElementById(`lactato-${index}`);const fcMediaInput=document.getElementById(`fc-media-${index}`);if(velocidadeInput&&velocidadeInput.value&&lactatoInput&&lactatoInput.value){estagios.push({velocidade:parseFloat(velocidadeInput.value),lactato:parseFloat(lactatoInput.value),fcMedia:fcMediaInput&&fcMediaInput.value?parseInt(fcMediaInput.value):null})}});estagios.sort((a,b)=>a.velocidade-b.velocidade);const lt1=detectarLimiar(estagios,2);const lt1VelocidadeElement=document.getElementById("lt1-velocidade");const lt1FcElement=document.getElementById("lt1-fc");const lt1PaceElement=document.getElementById("lt1-pace");if(lt1){lt1VelocidadeElement.textContent=lt1.velocidade.toFixed(1);lt1FcElement.textContent=lt1.fcMedia||"-";lt1PaceElement.textContent=velocidadeParaPace(lt1.velocidade)}else{lt1VelocidadeElement.textContent="-";lt1FcElement.textContent="-";lt1PaceElement.textContent="-"}const lt2=detectarLimiar(estagios,4);const lt2VelocidadeElement=document.getElementById("lt2-velocidade");const lt2FcElement=document.getElementById("lt2-fc");const lt2PaceElement=document.getElementById("lt2-pace");if(lt2){lt2VelocidadeElement.textContent=lt2.velocidade.toFixed(1);lt2FcElement.textContent=lt2.fcMedia||"-";lt2PaceElement.textContent=velocidadeParaPace(lt2.velocidade)}else{lt2VelocidadeElement.textContent="-";lt2FcElement.textContent="-";lt2PaceElement.textContent="-"}}function detectarLimiar(estagios,valorLimiar){if(estagios.length<2){return null}for(let i=0;i<estagios.length-1;i++){const estagio1=estagios[i];const estagio2=estagios[i+1];if(estagio1.lactato<=valorLimiar&&estagio2.lactato>=valorLimiar||estagio1.lactato>=valorLimiar&&estagio2.lactato<=valorLimiar){const percentual=(valorLimiar-estagio1.lactato)/(estagio2.lactato-estagio1.lactato);const velocidade=estagio1.velocidade+percentual*(estagio2.velocidade-estagio1.velocidade);let fcMedia=null;if(estagio1.fcMedia&&estagio2.fcMedia){fcMedia=Math.round(estagio1.fcMedia+percentual*(estagio2.fcMedia-estagio1.fcMedia))}return{velocidade:velocidade,fcMedia:fcMedia}}}return null}function velocidadeParaPace(velocidade){if(!velocidade||velocidade<=0){return"-"}const minutesPerkm=60/velocidade;const minutes=Math.floor(minutesPerkm);const seconds=Math.round((minutesPerkm-minutes)*60);return`${minutes}:${seconds.toString().padStart(2,"0")} min/km`}const formTeste=document.getElementById("form-teste");formTeste.addEventListener("submit",e=>{e.preventDefault();if(!formTeste.checkValidity()){formTeste.reportValidity();return}const alunoNome=document.getElementById("aluno-nome").value;const dataNascimento=document.getElementById("data-nascimento").value;const dataTeste=document.getElementById("data-teste").value;const estagios=[];const estagioItems=document.querySelectorAll(".estagio-item");estagioItems.forEach(item=>{const index=item.getAttribute("data-index");const velocidade=document.getElementById(`velocidade-${index}`).value;const lactato=document.getElementById(`lactato-${index}`).value;const fcMedia=document.getElementById(`fc-media-${index}`).value||null;const fcFinal=document.getElementById(`fc-final-${index}`).value||null;const pse=document.getElementById(`pse-${index}`).value||null;estagios.push({velocidade:parseFloat(velocidade),lactato:parseFloat(lactato),fcMedia:fcMedia?parseInt(fcMedia):null,fcFinal:fcFinal?parseInt(fcFinal):null,pse:pse?parseInt(pse):null})});const lt1Velocidade=document.getElementById("lt1-velocidade").textContent;const lt1Fc=document.getElementById("lt1-fc").textContent;const lt2Velocidade=document.getElementById("lt2-velocidade").textContent;const lt2Fc=document.getElementById("lt2-fc").textContent;const testeData={alunoNome:alunoNome,dataNascimento:dataNascimento,dataTeste:dataTeste,estagios:estagios,lt1:{velocidade:lt1Velocidade!=="-"?parseFloat(lt1Velocidade):null,fcMedia:lt1Fc!=="-"?parseInt(lt1Fc):null},lt2:{velocidade:lt2Velocidade!=="-"?parseFloat(lt2Velocidade):null,fcMedia:lt2Fc!=="-"?parseInt(lt2Fc):null}};gerarRelatorio(testeData)})});function gerarRelatorio(data){const jsonData=JSON.stringify(data);const encodedData=encodeURIComponent(jsonData);window.open(`report.html?data=${encodedData}`,"_blank")}